// Standalone test of the scoring algorithm ported verbatim from index.html.
// Run: node _scoring_test.mjs   (delete after — this is a throwaway gate)

function makeGame(framesRolls) {
  // framesRolls: array of 10 arrays of roll values
  return { frames: framesRolls.map(rolls => ({ rolls })) };
}

function frameComplete(game, idx) {
  const fr = game.frames[idx];
  if (idx < 9) {
    if (fr.rolls.length === 0) return false;
    if (fr.rolls[0] === 10) return true;
    return fr.rolls.length === 2;
  } else {
    const r = fr.rolls;
    if (r.length < 2) return false;
    if (r[0] === 10 || r[0] + r[1] === 10) return r.length === 3;
    return r.length === 2;
  }
}

function computeScores(game) {
  const f = game.frames;
  const rollsFlat = [];
  f.forEach(fr => fr.rolls.forEach(r => rollsFlat.push(r)));

  const cum = new Array(10).fill(null);
  let total = 0;
  let ri = 0;
  for (let frame = 0; frame < 10; frame++) {
    const fr = f[frame];
    if (fr.rolls.length === 0) { cum[frame] = null; continue; }

    if (frame < 9) {
      const first = rollsFlat[ri];
      if (first === 10) {
        const b1 = rollsFlat[ri + 1], b2 = rollsFlat[ri + 2];
        if (b1 == null || b2 == null) { cum[frame] = null; ri += 1; break; }
        total += 10 + b1 + b2;
        cum[frame] = total;
        ri += 1;
      } else {
        const second = rollsFlat[ri + 1];
        if (second == null) { cum[frame] = null; break; }
        if (first + second === 10) {
          const b1 = rollsFlat[ri + 2];
          if (b1 == null) { cum[frame] = null; ri += 2; break; }
          total += 10 + b1;
        } else {
          total += first + second;
        }
        cum[frame] = total;
        ri += 2;
      }
    } else {
      const sum = fr.rolls.reduce((a, b) => a + b, 0);
      if (frameComplete(game, 9)) { total += sum; cum[frame] = total; }
      else { cum[frame] = null; }
    }
  }
  return { cum, total };
}

function check(name, framesRolls, expected) {
  const g = makeGame(framesRolls);
  const { total } = computeScores(g);
  const ok = total === expected;
  console.log(`${ok ? "PASS" : "FAIL"}  ${name}: got ${total}, expected ${expected}`);
  return ok;
}

let all = true;

// Perfect game: 12 strikes -> 300
all &= check("perfect 300",
  [[10],[10],[10],[10],[10],[10],[10],[10],[10],[10,10,10]], 300);

// All 9s no spares (9,0 each) -> 90
all &= check("all 9-miss = 90",
  Array.from({length:9},()=>[9,0]).concat([[9,0]]), 90);

// All spares with 5: 5/ ... last frame 5,5,5 -> 150
all &= check("all 5-spares = 150",
  Array.from({length:9},()=>[5,5]).concat([[5,5,5]]), 150);

// All gutters -> 0
all &= check("all gutters = 0",
  Array.from({length:10},()=>[0,0]), 0);

// Classic mixed game from Wikipedia-style example:
// frames: 1/(spare) X 7 2 ... let's use a well-known one:
// 9/ 9/ 9/ 9/ 9/ 9/ 9/ 9/ 9/ 9/9  -> 190 (nine spares then 9 spare + 9 bonus? )
// Easier verified case: X 7/ 9 0 X 0 8 8/ ... use a textbook:
// Roll sequence with known total 168 (a common example):
// frames: [10],[7,3],[9,0],[10],[0,8],[8,2],[0,6],[10],[10],[10,8,1]
// compute by hand:
// F1: 10 + (7+3)=20 ->20
// F2: 7+3=10 +9 (next1)=19 ->39
// F3: 9+0=9 ->48
// F4: 10 + (0+8)=18 ->66
// F5: 0+8=8 ->74
// F6: 8+2=10 spare + next1=0 ->10 ->84
// F7: 0+6=6 ->90
// F8: 10 + next two (10,10)=30 ->120  (next two are F9 strike=10, F10 ball1=10)
// F9: 10 + next two (10, 8)=28 ->148  (F10 ball1=10, ball2=8)
// F10: 10+8+1=19 ->167
all &= check("textbook mixed = 167",
  [[10],[7,3],[9,0],[10],[0,8],[8,2],[0,6],[10],[10],[10,8,1]], 167);

// 10th frame open (no bonus): all strikes first 9, then 10th = 3,4 -> ?
// F1..F8 each strike worth 10+next two.
// frames 1-7 strikes: each 10+10+10=30 => 7*30=210 ... F8: 10 + F9(10) + F10b1(3) = 23 ->233
// F9: 10 + F10b1(3)+F10b2(4)=17 ->250 ; F10 open: 3+4=7 ->257
all &= check("9 strikes then 3,4 = 257",
  [[10],[10],[10],[10],[10],[10],[10],[10],[10],[3,4]], 257);

// 10th frame spare with bonus: 9 strikes then 5/ +X? -> ball3 strike
// all strikes 1-9, 10th = 5,5,10
// F1-7 strikes 30 each =210; F8:10+10+5=25 ->235; F9:10+5+5=20 ->255; F10:5+5+10=20 ->275
all &= check("9 strikes then 5/X = 275",
  [[10],[10],[10],[10],[10],[10],[10],[10],[10],[5,5,10]], 275);

console.log(all ? "\nALL PASS" : "\nSOME FAILED");
process.exit(all ? 0 : 1);

